const item = $input.item.json;
const previewText = String(item.preview_text || '');
const sourceUrl = String(item.source_url || '');
const platform = String(item.source_platform || '');
const risk = item.preview_risk_score;
const oid = item.outreach_item_id;

const headerText = `:memo: *Outreach item #${oid}* — \`${platform}\` — risk *${risk}/100*\n><${sourceUrl}|source>\n>${previewText.replace(/\n/g, '\n>')}`;

const formUrl = `https://n8n.corbello.io/webhook/render-approval-form?outreach_item_id=${oid}`;

const baseButtons = [
  {type: 'button', text: {type: 'plain_text', text: 'Reject'}, action_id: `reject_${oid}`, style: 'danger'},
  {type: 'button', text: {type: 'plain_text', text: 'Open full form'}, url: formUrl},
];

const approveButton = {type: 'button', text: {type: 'plain_text', text: 'Approve helpful-only as-drafted'}, action_id: `approve_${oid}`, style: 'primary'};

const lowRisk = risk < 20;
const buttons = lowRisk ? [approveButton, ...baseButtons] : baseButtons;

const blocks = [
  {type: 'section', text: {type: 'mrkdwn', text: headerText}},
  {type: 'actions', elements: buttons},
];

return [{
  json: {
    ...item,
    slack_blocks: blocks,
    slack_text_fallback: `Outreach item #${oid} — risk ${risk}/100 — needs review`,
    is_low_risk: lowRisk,
  }
}];

const rawId = $('Webhook GET Render Form').item.json.query?.outreach_item_id;
const parsed = parseInt(rawId, 10);
if (isNaN(parsed) || parsed <= 0) {
  return [{json: {invalid: true, html: '<h1>Missing or invalid outreach_item_id parameter</h1>'}}];
}
return [{json: {invalid: false, outreach_item_id: parsed}}];

function sha256(str) {
  const bytes = [];
  for (let i = 0; i < str.length; i++) {
    let c = str.charCodeAt(i);
    if (c < 0x80) { bytes.push(c); }
    else if (c < 0x800) { bytes.push(0xC0|(c>>6), 0x80|(c&0x3F)); }
    else if (c < 0xD800 || c >= 0xE000) { bytes.push(0xE0|(c>>12), 0x80|((c>>6)&0x3F), 0x80|(c&0x3F)); }
    else { i++; c=0x10000+(((c&0x3FF)<<10)|(str.charCodeAt(i)&0x3FF)); bytes.push(0xF0|(c>>18),0x80|((c>>12)&0x3F),0x80|((c>>6)&0x3F),0x80|(c&0x3F)); }
  }
  const K=[0x428a2f98,0x71374491,0xb5c0fbcf,0xe9b5dba5,0x3956c25b,0x59f111f1,0x923f82a4,0xab1c5ed5,0xd807aa98,0x12835b01,0x243185be,0x550c7dc3,0x72be5d74,0x80deb1fe,0x9bdc06a7,0xc19bf174,0xe49b69c1,0xefbe4786,0x0fc19dc6,0x240ca1cc,0x2de92c6f,0x4a7484aa,0x5cb0a9dc,0x76f988da,0x983e5152,0xa831c66d,0xb00327c8,0xbf597fc7,0xc6e00bf3,0xd5a79147,0x06ca6351,0x14292967,0x27b70a85,0x2e1b2138,0x4d2c6dfc,0x53380d13,0x650a7354,0x766a0abb,0x81c2c92e,0x92722c85,0xa2bfe8a1,0xa81a664b,0xc24b8b70,0xc76c51a3,0xd192e819,0xd6990624,0xf40e3585,0x106aa070,0x19a4c116,0x1e376c08,0x2748774c,0x34b0bcb5,0x391c0cb3,0x4ed8aa4a,0x5b9cca4f,0x682e6ff3,0x748f82ee,0x78a5636f,0x84c87814,0x8cc70208,0x90befffa,0xa4506ceb,0xbef9a3f7,0xc67178f2];
  let h0=0x6a09e667,h1=0xbb67ae85,h2=0x3c6ef372,h3=0xa54ff53a,h4=0x510e527f,h5=0x9b05688c,h6=0x1f83d9ab,h7=0x5be0cd19;
  const msgLen=bytes.length; bytes.push(0x80);
  while((bytes.length%64)!==56) bytes.push(0);
  const bitLen=msgLen*8; bytes.push(0,0,0,0,(bitLen>>>24)&0xFF,(bitLen>>>16)&0xFF,(bitLen>>>8)&0xFF,bitLen&0xFF);
  function rotr(x,n){return(x>>>n)|(x<<(32-n));}
  function ch(x,y,z){return(x&y)^(~x&z);}
  function maj(x,y,z){return(x&y)^(x&z)^(y&z);}
  function sig0(x){return rotr(x,2)^rotr(x,13)^rotr(x,22);}
  function sig1(x){return rotr(x,6)^rotr(x,11)^rotr(x,25);}
  function gam0(x){return rotr(x,7)^rotr(x,18)^(x>>>3);}
  function gam1(x){return rotr(x,17)^rotr(x,19)^(x>>>10);}
  for(let offset=0;offset<bytes.length;offset+=64){
    const w=new Array(64);
    for(let i=0;i<16;i++) w[i]=((bytes[offset+i*4]<<24)|(bytes[offset+i*4+1]<<16)|(bytes[offset+i*4+2]<<8)|bytes[offset+i*4+3])>>>0;
    for(let i=16;i<64;i++) w[i]=(gam1(w[i-2])+w[i-7]+gam0(w[i-15])+w[i-16])>>>0;
    let a=h0,b=h1,c=h2,d=h3,e=h4,f=h5,g=h6,h=h7;
    for(let i=0;i<64;i++){const t1=(h+sig1(e)+ch(e,f,g)+K[i]+w[i])>>>0;const t2=(sig0(a)+maj(a,b,c))>>>0;h=g;g=f;f=e;e=(d+t1)>>>0;d=c;c=b;b=a;a=(t1+t2)>>>0;}
    h0=(h0+a)>>>0;h1=(h1+b)>>>0;h2=(h2+c)>>>0;h3=(h3+d)>>>0;h4=(h4+e)>>>0;h5=(h5+f)>>>0;h6=(h6+g)>>>0;h7=(h7+h)>>>0;
  }
  function hex(n){return('00000000'+(n>>>0).toString(16)).slice(-8);}
  return hex(h0)+hex(h1)+hex(h2)+hex(h3)+hex(h4)+hex(h5)+hex(h6)+hex(h7);
}

const body = $input.item.json.body;

if (!body) {
  throw new Error('No form body received — expected application/x-www-form-urlencoded POST');
}

const VALID_DECISIONS = ['approved', 'rejected', 'manual_only', 'save_for_later'];
const decision = body.decision;
if (!decision || !VALID_DECISIONS.includes(decision)) {
  throw new Error('Invalid decision "' + decision + '". Must be one of: ' + VALID_DECISIONS.join(', '));
}

const chosen = body.chosen_variant || 'helpful_only';
const editedText = body['text_' + chosen];
const originalText = body['original_text_' + chosen];
const chosenDraftId = parseInt(body['draft_id_' + chosen], 10);

if (isNaN(chosenDraftId) || chosenDraftId <= 0) {
  throw new Error('Invalid or missing draft_id_' + chosen + ': "' + body['draft_id_' + chosen] + '"');
}

if (editedText === undefined || editedText === null) {
  throw new Error('Missing text_' + chosen + ' field in form submission');
}

const outreachItemId = parseInt(body.outreach_item_id, 10);
if (isNaN(outreachItemId) || outreachItemId <= 0) {
  throw new Error('Invalid or missing outreach_item_id: "' + body.outreach_item_id + '"');
}

const wasEdited = editedText !== originalText;
const finalText = editedText;
const destination = body.approved_destination || '';
const postType = body.approved_post_type || '';
const hash = sha256(finalText + destination + postType);

return [{json: {
  draft_id: chosenDraftId,
  outreach_item_id: outreachItemId,
  approved_by: 'jeremy',
  decision: decision,
  edited_text: wasEdited ? finalText : null,
  approved_destination: destination,
  approved_post_type: postType,
  approved_content_hash: hash,
  approval_notes: body.notes || null,
}}];

parameters.query:
INSERT INTO approvals (draft_id, approved_by, decision, edited_text, approved_destination, approved_post_type, approved_content_hash, approval_notes)
VALUES ($1, $2, $3, $4, $5, $6, $7, $8)
RETURNING id;
